class Solution {
public:
    vector<int> beautifulIndices(string s, string a, string b, int k) {
        vector<int> res;
        for (int i = 0; i < s.length(); i++) {
            if (s.substr(i, a.length()) == a) {
                int j = -1;
                for (int x = 0; x < s.length(); x++) {
                    if (s.substr(x, b.length()) == b) {
                        j = x;
                        break;
                    }
                }
                if (j != -1 && abs(i - j) <= k) {
                    res.push_back(i);
                }
            }
        }
        sort(res.begin(), res.end());
        return res;
    }
};
```

